     1→/**
     2→ * Claude Code SDK API Routes
     3→ * RESTful endpoints for full Claude Code SDK integration
     4→ *
     5→ * Features:
     6→ * - Session management (streaming & headless)
     7→ * - Real-time communication (WebSocket & SSE)
     8→ * - Context management and optimization
     9→ * - Security controls and audit logging
    10→ * - Error handling and recovery
    11→ */
    12→
    13→import express, { Request, Response, NextFunction } from 'express';
    14→import { Server as SocketIOServer } from 'socket.io';
    15→import { getClaudeCodeSDKManager, SystemConfiguration } from '../services/ClaudeCodeSDKManager';
    16→import { authenticate, authorize } from '../middleware/auth';
    17→import { rateLimiter } from '../middleware/rate-limit';
    18→import { validateRequest } from '../middleware/validation';
    19→import { errorHandler } from '../middleware/error-handler';
    20→
    21→const router = express.Router();
    22→
    23→// Initialize SDK Manager with configuration
    24→const sdkManager = getClaudeCodeSDKManager({
    25→  claude: {
    26→    apiKey: process.env.ANTHROPIC_API_KEY!,
    27→    workingDirectory: process.env.CLAUDE_WORKING_DIRECTORY || '/workspaces/agent-feed/prod',
    28→    dangerousMode: process.env.CLAUDE_DANGEROUS_MODE === 'true',
    29→    maxConcurrentSessions: parseInt(process.env.CLAUDE_MAX_CONCURRENT_SESSIONS || '10'),
    30→    defaultToolPermissions: {
    31→      fileSystem: {
    32→        read: ['/workspaces/agent-feed/prod/**'],
    33→        write: ['/workspaces/agent-feed/prod/temp/**', '/workspaces/agent-feed/prod/logs/**'],
    34→        execute: ['/workspaces/agent-feed/prod/scripts/**']
    35→      },
    36→      network: {
    37→        allowHttp: true,
    38→        allowedDomains: ['api.anthropic.com', 'github.com'],
    39→        allowedPorts: [80, 443, 3000, 8000]
    40→      },
    41→      system: {
    42→        allowBash: true,
    43→        allowedCommands: ['ls', 'cat', 'grep', 'find', 'npm', 'node'],
    44→        dangerousMode: process.env.CLAUDE_DANGEROUS_MODE === 'true'
    45→      },
    46→      tools: {
    47→        allowed: ['Read', 'Write', 'Edit', 'Bash', 'Grep', 'Glob', 'WebSearch'],
    48→        restricted: ['KillShell'],
    49→        customLimits: {}
    50→      }
    51→    }
    52→  },
    53→  session: {
    54→    defaultTimeout: parseInt(process.env.SESSION_TIMEOUT || '3600000'), // 1 hour
    55→    maxContextSize: parseInt(process.env.CONTEXT_MAX_SIZE || '100000'),
    56→    autoCompactionThreshold: parseInt(process.env.AUTO_COMPACTION_THRESHOLD || '80000'),
    57→    snapshotInterval: parseInt(process.env.SNAPSHOT_INTERVAL || '300000') // 5 minutes
    58→  },
    59→  security: {
    60→    requireAuthentication: process.env.REQUIRE_AUTHENTICATION !== 'false',
    61→    auditLevel: process.env.AUDIT_LEVEL as 'basic' | 'verbose' | 'complete' || 'verbose',
    62→    maxResourceUsage: {
    63→      maxMemoryUsage: parseInt(process.env.MAX_MEMORY_USAGE || '1000000000'), // 1GB
    64→      maxCpuUsage: parseInt(process.env.MAX_CPU_USAGE || '80'), // 80%
    65→      maxDiskUsage: parseInt(process.env.MAX_DISK_USAGE || '5000000000'), // 5GB
    66→      maxNetworkUsage: parseInt(process.env.MAX_NETWORK_USAGE || '1000000000'), // 1GB
    67→      maxConcurrentOperations: parseInt(process.env.MAX_CONCURRENT_OPERATIONS || '5')
    68→    }
    69→  },
    70→  monitoring: {
    71→    enableMetrics: process.env.ENABLE_METRICS === 'true',
    72→    enableAlerts: process.env.ENABLE_ALERTS === 'true',
    73→    logLevel: process.env.LOG_LEVEL as 'error' | 'warn' | 'info' | 'debug' || 'info'
    74→  }
    75→});
    76→
    77→// Middleware
    78→router.use(rateLimiter);
    79→router.use(authenticate);
    80→
    81→// ========================================
    82→// SESSION MANAGEMENT ENDPOINTS
    83→// ========================================
    84→
    85→/**
    86→ * POST /api/claude/sessions
    87→ * Create a new session (streaming or headless)
    88→ */
    89→router.post('/sessions',
    90→  authorize(['user', 'admin']),
    91→  validateRequest({
    92→    body: {
    93→      type: { type: 'string', enum: ['streaming', 'headless'], required: true },
    94→      workingDirectory: { type: 'string', required: false },
    95→      toolPermissions: { type: 'object', required: false },
    96→      contextSize: { type: 'number', required: false }
    97→    }
    98→  }),
    99→  async (req: Request, res: Response, next: NextFunction) => {
   100→    try {
   101→      const { type, workingDirectory, toolPermissions, contextSize } = req.body;
   102→      const userId = req.user.id;
   103→
   104→      if (type === 'streaming') {
   105→        const streamingSession = await sdkManager.createStreamingSession(userId, {
   106→          workingDirectory,
   107→          toolPermissions,
   108→          contextSettings: contextSize ? { maxSize: contextSize } : undefined
   109→        });
   110→
   111→        res.status(201).json({
   112→          success: true,
   113→          session: {
   114→            id: streamingSession.id,
   115→            type: 'streaming',
   116→            status: 'active',
   117→            created: new Date().toISOString()
   118→          },
   119→          endpoints: {
   120→            stream: `/api/claude/sessions/${streamingSession.id}/stream`,
   121→            websocket: `/ws/claude/sessions/${streamingSession.id}`,
   122→            status: `/api/claude/sessions/${streamingSession.id}`
   123→          }
   124→        });
   125→      } else {
   126→        // For headless sessions, we'll create them on-demand during task execution
   127→        res.status(201).json({
   128→          success: true,
   129→          message: 'Headless sessions are created automatically during task execution',
   130→          endpoint: '/api/claude/tasks'
   131→        });
   132→      }
   133→
   134→    } catch (error) {
   135→      next(error);
   136→    }
   137→  }
   138→);
   139→
   140→/**
   141→ * GET /api/claude/sessions/:sessionId
   142→ * Get session details and status
   143→ */
   144→router.get('/sessions/:sessionId',
   145→  authorize(['user', 'admin']),
   146→  async (req: Request, res: Response, next: NextFunction) => {
   147→    try {
   148→      const { sessionId } = req.params;
   149→      const session = await sdkManager.getSession(sessionId);
   150→
   151→      if (!session) {
   152→        return res.status(404).json({
   153→          success: false,
   154→          error: 'Session not found'
   155→        });
   156→      }
   157→
   158→      // Check ownership
   159→      if (session.userId !== req.user.id && !['admin', 'moderator'].includes(req.user.role)) {
   160→        return res.status(403).json({
   161→          success: false,
   162→          error: 'Access denied'
   163→        });
   164→      }
   165→
   166→      const metrics = await sdkManager.getSystemMetrics();
   167→
   168→      res.json({
   169→        success: true,
   170→        session: {
   171→          id: session.id,
   172→          type: session.type,
   173→          status: session.status,
   174→          created: session.created,
   175→          lastActivity: session.lastActivity,
   176→          configuration: session.configuration,
   177→          metrics: session.metrics
   178→        },
   179→        systemMetrics: metrics
   180→      });
   181→
   182→    } catch (error) {
   183→      next(error);
   184→    }
   185→  }
   186→);
   187→
   188→/**
   189→ * PUT /api/claude/sessions/:sessionId
   190→ * Update session configuration
   191→ */
   192→router.put('/sessions/:sessionId',
   193→  authorize(['user', 'admin']),
   194→  validateRequest({
   195→    body: {
   196→      toolPermissions: { type: 'object', required: false },
   197→      contextSettings: { type: 'object', required: false },
   198→      dangerousMode: { type: 'object', required: false }
   199→    }
   200→  }),
   201→  async (req: Request, res: Response, next: NextFunction) => {
   202→    try {
   203→      const { sessionId } = req.params;
   204→      const { toolPermissions, contextSettings, dangerousMode } = req.body;
   205→
   206→      const session = await sdkManager.getSession(sessionId);
   207→      if (!session || session.userId !== req.user.id) {
   208→        return res.status(404).json({
   209→          success: false,
   210→          error: 'Session not found or access denied'
   211→        });
   212→      }
   213→
   214→      // Update tool permissions if provided
   215→      if (toolPermissions) {
   216→        await sdkManager.updateSessionPermissions(sessionId, toolPermissions);
   217→      }
   218→
   219→      // Enable dangerous mode if requested (requires special authorization)
   220→      if (dangerousMode && dangerousMode.enabled) {
   221→        if (!['admin'].includes(req.user.role)) {
   222→          return res.status(403).json({
   223→            success: false,
   224→            error: 'Dangerous mode requires admin privileges'
   225→          });
   226→        }
   227→
   228→        await sdkManager.enableDangerousMode(sessionId, {
   229→          ...dangerousMode,
   230→          approver: req.user.id
   231→        });
   232→      }
   233→
   234→      res.json({
   235→        success: true,
   236→        message: 'Session updated successfully',
   237→        timestamp: new Date().toISOString()
   238→      });
   239→
   240→    } catch (error) {
   241→      next(error);
   242→    }
   243→  }
   244→);
   245→
   246→/**
   247→ * DELETE /api/claude/sessions/:sessionId
   248→ * Terminate a session
   249→ */
   250→router.delete('/sessions/:sessionId',
   251→  authorize(['user', 'admin']),
   252→  async (req: Request, res: Response, next: NextFunction) => {
   253→    try {
   254→      const { sessionId } = req.params;
   255→      const { reason } = req.body;
   256→
   257→      const session = await sdkManager.getSession(sessionId);
   258→      if (!session || session.userId !== req.user.id) {
   259→        return res.status(404).json({
   260→          success: false,
   261→          error: 'Session not found or access denied'
   262→        });
   263→      }
   264→
   265→      await sdkManager.terminateSession(sessionId, reason);
   266→
   267→      res.json({
   268→        success: true,
   269→        message: 'Session terminated successfully',
   270→        timestamp: new Date().toISOString()
   271→      });
   272→
   273→    } catch (error) {
   274→      next(error);
   275→    }
   276→  }
   277→);
