   279→// ========================================
   280→// STREAMING COMMUNICATION ENDPOINTS
   281→// ========================================
   282→
   283→/**
   284→ * POST /api/claude/sessions/:sessionId/stream
   285→ * Send message to streaming session
   286→ */
   287→router.post('/sessions/:sessionId/stream',
   288→  authorize(['user', 'admin']),
   289→  validateRequest({
   290→    body: {
   291→      message: { type: 'object', required: true },
   292→      attachments: { type: 'array', required: false }
   293→    }
   294→  }),
   295→  async (req: Request, res: Response, next: NextFunction) => {
   296→    try {
   297→      const { sessionId } = req.params;
   298→      const { message, attachments } = req.body;
   299→
   300→      const streamingSession = sdkManager.getStreamingSession(sessionId);
   301→      if (!streamingSession) {
   302→        return res.status(404).json({
   303→          success: false,
   304→          error: 'Streaming session not found'
   305→        });
   306→      }
   307→
   308→      // Validate session ownership
   309→      const session = await sdkManager.getSession(sessionId);
   310→      if (!session || session.userId !== req.user.id) {
   311→        return res.status(403).json({
   312→          success: false,
   313→          error: 'Access denied'
   314→        });
   315→      }
   316→
   317→      await streamingSession.sendMessage({
   318→        ...message,
   319→        attachments,
   320→        timestamp: new Date().toISOString()
   321→      });
   322→
   323→      res.json({
   324→        success: true,
   325→        message: 'Message sent successfully',
   326→        timestamp: new Date().toISOString()
   327→      });
   328→
   329→    } catch (error) {
   330→      next(error);
   331→    }
   332→  }
   333→);
   334→
   335→/**
   336→ * GET /api/claude/sessions/:sessionId/stream
   337→ * Server-Sent Events endpoint for streaming responses
   338→ */
   339→router.get('/sessions/:sessionId/stream',
   340→  authorize(['user', 'admin']),
   341→  async (req: Request, res: Response, next: NextFunction) => {
   342→    try {
   343→      const { sessionId } = req.params;
   344→
   345→      const streamingSession = sdkManager.getStreamingSession(sessionId);
   346→      if (!streamingSession) {
   347→        return res.status(404).json({
   348→          success: false,
   349→          error: 'Streaming session not found'
   350→        });
   351→      }
   352→
   353→      // Validate session ownership
   354→      const session = await sdkManager.getSession(sessionId);
   355→      if (!session || session.userId !== req.user.id) {
   356→        return res.status(403).json({
   357→          success: false,
   358→          error: 'Access denied'
   359→        });
   360→      }
   361→
   362→      // Setup SSE
   363→      res.writeHead(200, {
   364→        'Content-Type': 'text/event-stream',
   365→        'Cache-Control': 'no-cache',
   366→        'Connection': 'keep-alive',
   367→        'Access-Control-Allow-Origin': '*',
   368→        'Access-Control-Allow-Headers': 'Cache-Control'
   369→      });
   370→
   371→      // Send initial connection event
   372→      res.write(`data: ${JSON.stringify({
   373→        type: 'connection',
   374→        data: { status: 'connected', sessionId },
   375→        timestamp: new Date().toISOString()
   376→      })}\n\n`);
   377→
   378→      // Subscribe to session events
   379→      const unsubscribe = streamingSession.subscribe((event) => {
   380→        res.write(`data: ${JSON.stringify(event)}\n\n`);
   381→      });
   382→
   383→      // Handle client disconnect
   384→      req.on('close', () => {
   385→        unsubscribe();
   386→      });
   387→
   388→      // Keep connection alive
   389→      const keepAlive = setInterval(() => {
   390→        res.write(`data: ${JSON.stringify({
   391→          type: 'heartbeat',
   392→          timestamp: new Date().toISOString()
   393→        })}\n\n`);
   394→      }, 30000);
   395→
   396→      req.on('close', () => {
   397→        clearInterval(keepAlive);
   398→        unsubscribe();
   399→      });
   400→
   401→    } catch (error) {
   402→      next(error);
   403→    }
   404→  }
   405→);
