   618→// ========================================
   619→// WEBSOCKET SETUP FOR REAL-TIME COMMUNICATION
   620→// ========================================
   621→
   622→export function setupWebSocketRoutes(io: SocketIOServer): void {
   623→  const claudeNamespace = io.of('/claude');
   624→
   625→  claudeNamespace.on('connection', (socket) => {
   626→    console.log(`Claude WebSocket client connected: ${socket.id}`);
   627→
   628→    socket.on('join-session', async (data) => {
   629→      try {
   630→        const { sessionId, token } = data;
   631→
   632→        // Validate token and session ownership
   633→        // Implementation depends on authentication system
   634→
   635→        socket.join(sessionId);
   636→
   637→        const streamingSession = sdkManager.getStreamingSession(sessionId);
   638→        if (streamingSession) {
   639→          // Subscribe to session events
   640→          const unsubscribe = streamingSession.subscribe((event) => {
   641→            socket.emit('session-event', event);
   642→          });
   643→
   644→          socket.on('disconnect', () => {
   645→            unsubscribe();
   646→          });
   647→
   648→          socket.emit('joined-session', { sessionId, status: 'connected' });
   649→        } else {
   650→          socket.emit('error', { message: 'Session not found' });
   651→        }
   652→
   653→      } catch (error) {
   654→        socket.emit('error', { message: error.message });
   655→      }
   656→    });
   657→
   658→    socket.on('send-message', async (data) => {
   659→      try {
   660→        const { sessionId, message } = data;
   661→
   662→        const streamingSession = sdkManager.getStreamingSession(sessionId);
   663→        if (streamingSession) {
